export interface LanguageOption {
  code: string;
  label: string;
}

export const defaultLng = "en";

export const reviewedUiLanguages: LanguageOption[] = [
  { code: "en", label: "English" },
  { code: "zh", label: "中文" },
  { code: "tc", label: "繁體中文" },
  { code: "es", label: "Español" },
  { code: "ko", label: "한국어" },
];

export const dexLanguageOptions: LanguageOption[] = [
  ...reviewedUiLanguages,
  { code: "ja", label: "日本語" },
  { code: "vi", label: "Tiếng Việt" },
  { code: "de", label: "Deutsch" },
  { code: "fr", label: "Français" },
  { code: "ru", label: "Русский" },
  { code: "id", label: "Bahasa Indonesia" },
  { code: "tr", label: "Türkçe" },
  { code: "it", label: "Italiano" },
  { code: "pt", label: "Português" },
  { code: "uk", label: "Українська" },
  { code: "pl", label: "Polski" },
  { code: "nl", label: "Nederlands" },
  { code: "ar", label: "العربية" },
  { code: "fa", label: "فارسی" },
  { code: "he", label: "עברית" },
];

export const legacyLanguageAliases: Record<string, string> = {
  sc: "zh",
  "zh-cn": "zh",
  "zh-hans": "zh",
  "zh-tw": "tc",
  "zh-hant": "tc",
};

export const supportedLngs = Array.from(
  new Set([
    ...dexLanguageOptions.map(language => language.code),
    ...Object.keys(legacyLanguageAliases),
  ])
);

export function normalizeLanguageCode(value?: string | null): string | null {
  const normalized = value?.trim().toLowerCase();
  if (!normalized) return null;
  const canonical = legacyLanguageAliases[normalized] || normalized;
  if (supportedLngs.includes(canonical)) return canonical;
  const baseCode = canonical.split("-")[0];
  return supportedLngs.includes(baseCode) ? baseCode : null;
}

export function getLocaleResourceCode(lng: string): string {
  const normalized = normalizeLanguageCode(lng) || defaultLng;
  return normalized === "zh" ? "sc" : normalized;
}

export function getLanguageOption(code?: string | null): LanguageOption {
  const normalized = normalizeLanguageCode(code) || defaultLng;
  return (
    dexLanguageOptions.find(language => language.code === normalized) ||
    reviewedUiLanguages[0]
  );
}
